#include <bits/stdc++.h>
using namespace std;
struct Stu{
    string name;
    int y,m,d,id;
}a[102];
bool cmp(Stu u,Stu v){
    if(u.y==v.y){
        if(u.m==v.m){
            if(u.d==v.d)
                return u.id>v.id;
            return u.d<v.d;
        }
        return u.m<v.m;
    }
    return u.y<v.y;
}
int n;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i].name>>a[i].y>>a[i].m>>a[i].d;
        a[i].id=i;
    }
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=n;i++)
        cout<<a[i].name<<'\n';
    return 0;
}
